    /// Returns the localized ARIA label for this segment kind.
    #[must_use]
    pub fn aria_label(&self, messages: &Messages, locale: &Locale) -> String {
        fn call(
            message: &MessageFn<dyn Fn(&Locale) -> String + Send + Sync>,
            locale: &Locale,
        ) -> String {
            message(locale)
        }

