#[derive(Clone, Debug, PartialEq, Eq, Hash)]
pub struct CalendarDateTime {
    date: CalendarDate,
    time: Time,
}

impl CalendarDateTime {
    /// Creates a date-time from its date and time parts.
    #[must_use]
    pub const fn new(date: CalendarDate, time: Time) -> Self {
        Self { date, time }
    }

    /// Returns the date portion.
    #[must_use]
    pub const fn date(&self) -> &CalendarDate {
        &self.date
    }

    /// Returns the time portion.
    #[must_use]
    pub const fn time(&self) -> &Time {
        &self.time
    }

    /// Adds a duration.
    ///
    /// # Errors
    ///
    /// Returns an error if the arithmetic result cannot be represented.
    pub fn add(&self, duration: DateTimeDuration) -> Result<Self, CalendarError> {
        let current = temporal_date_time_for(self)?;

        let next = current
            .add(&duration.to_temporal()?, Some(Overflow::Constrain))
            .map_err(|error| CalendarError::Arithmetic(error.to_string()))?;

        from_temporal_datetime(self.date.calendar, &next)
    }

    /// Subtracts a duration.
    ///
    /// # Errors
    ///
    /// Returns an error if the arithmetic result cannot be represented.
    pub fn subtract(&self, duration: DateTimeDuration) -> Result<Self, CalendarError> {
        self.add(DateTimeDuration {
            date: DateDuration {
                years: checked_neg_i32_for_calendar(duration.date.years, "year")?,
                months: checked_neg_i32_for_calendar(duration.date.months, "month")?,
                weeks: checked_neg_i32_for_calendar(duration.date.weeks, "week")?,
                days: checked_neg_i32_for_calendar(duration.date.days, "day")?,
            },
            time: TimeDuration {
                hours: checked_neg_i64_for_calendar(duration.time.hours, "hour")?,
                minutes: checked_neg_i64_for_calendar(duration.time.minutes, "minute")?,
                seconds: checked_neg_i64_for_calendar(duration.time.seconds, "second")?,
                milliseconds: checked_neg_i64_for_calendar(
                    duration.time.milliseconds,
                    "millisecond",
                )?,
                microseconds: checked_neg_i64_for_calendar(
                    duration.time.microseconds,
                    "microsecond",
                )?,
                nanoseconds: checked_neg_i64_for_calendar(duration.time.nanoseconds, "nanosecond")?,
            },
        })
    }

    /// Returns a copy with selected fields replaced.
    ///
    /// # Errors
    ///
    /// Returns an error if either the replacement date fields or replacement
    /// time fields are invalid.
    pub fn set(
        &self,
        date_fields: &CalendarDateFields,
        time_fields: TimeFields,
    ) -> Result<Self, CalendarError> {
        let next_date = if calendar_fields_are_empty(date_fields) {
            self.date.clone()
        } else {
            self.date.set(date_fields)?
        };

        Ok(Self {
            date: next_date,
            time: self

