732	/// Builds the plan for a user-driven request to open or close the popover.
733	///
734	/// When `open` is **controlled** (`props.open.is_some()`), the [`State`] is not
735	/// mutated: the request is recorded in [`Context::requested_open`] (and the
736	/// `focus` intent in `requested_focus`) and signalled via [`Effect::OpenChange`]
737	/// so the parent reconciles by updating the `open` prop — the focus effect then
738	/// fires from `SyncProps` once the state actually lands. When **uncontrolled**,
739	/// the `State` transitions and the `focus` effect fires immediately.
740	///
741	/// Returns `None` when the popover is already in the requested open state.
742	fn open_request(
743	    state: &State,
744	    ctx: &Context,
745	    props: &Props,
746	    target_open: bool,
747	    focus: OpenFocus,
748	) -> Option<TransitionPlan<Machine>> {
749	    if (*state == State::Open) == target_open {
750	        // Already in the requested open-state, so there is nothing to
751	        // reconcile. A controlled open the parent vetoed (left `open`
752	        // unchanged) leaves a deferred focus intent in `requested_focus` with no
753	        // `SyncProps` to consume it; a subsequent no-op *close* (e.g. `FocusOut`
754	        // after the input lost focus) cancels that stale intent so a later
755	        // programmatic open uses the per-direction default (`FocusCalendar`)
756	        // instead of suppressing it. (`requested_focus` is only ever set under
757	        // controlled `open`, so the uncontrolled no-op path stays a pure `None`.)
758	        if !target_open && ctx.requested_focus.is_some() {
759	            return Some(TransitionPlan::new().apply(|ctx: &mut Context| {
760	                ctx.requested_focus = None;
761	            }));
762	        }
763	        return None;
764	    }
765	
766	    let controlled = props.open.is_some();
767	    let mut plan = if controlled {
768	        TransitionPlan::new()
769	    } else {
770	        TransitionPlan::to(if target_open {
771	            State::Open
772	        } else {
773	            State::Closed
774	        })
775	    };
776	
777	    plan = plan
778	        .apply(move |ctx: &mut Context| {
779	            ctx.requested_open = target_open;
780	            if controlled {
781	                // Defer the focus move to `SyncProps`, which lands the state.
782	                ctx.requested_focus = Some(focus);
783	            }
784	        })
785	        .with_effect(open_change_effect());
786	
787	    if !controlled && let Some(focus) = focus.effect() {
788	        plan = plan.with_effect(focus);
789	    }
790	
791	    Some(plan)
792	}
