    }));
    assert_eq!(
        svc.context().segment_value(DateSegmentKind::DayPeriod),
        Some(1)
    );

    drop(svc.send(Event::TypeIntoSegment {
        segment: DateSegmentKind::DayPeriod,
        ch: 'a',
    }));
    assert_eq!(
        svc.context().segment_value(DateSegmentKind::DayPeriod),
        Some(0)
    );
}

