fn numeric_field_order_from_formatted(formatted: &str) -> Option<DateOrder> {
    #[derive(Clone, Copy, PartialEq, Eq)]
    enum DateComponent {
        Month,
        Day,
        Year,
    }

    // Transliterate native decimal digits (e.g. Extended Arabic-Indic for
    // `fa-IR`, Arabic-Indic for `ar-EG`) to ASCII so the probe's year/month/day
    // values are recognised regardless of the locale's numbering system.
    let formatted = crate::number::normalize_digits(formatted);

    let mut numeric_runs = Vec::new();

    let mut current: Option<u32> = None;

    for ch in formatted.chars() {
        if let Some(digit) = ch.to_digit(10) {
            current = Some(current.unwrap_or(0).checked_mul(10)?.checked_add(digit)?);
        } else if let Some(value) = current.take() {
            numeric_runs.push(value);
        }
    }

    if let Some(value) = current {
        numeric_runs.push(value);
    }

    let components: Vec<_> = numeric_runs
        .into_iter()
        .filter_map(|value| match value {
            11 => Some(DateComponent::Month),
            22 => Some(DateComponent::Day),
            6 | 2006 => Some(DateComponent::Year),
            _ => None,
        })
        .collect();

    match components.as_slice() {
        [
            DateComponent::Month,
            DateComponent::Day,
            DateComponent::Year,
        ] => Some(DateOrder::MonthDayYear),

        [
            DateComponent::Day,
            DateComponent::Month,
            DateComponent::Year,
        ] => Some(DateOrder::DayMonthYear),

        [
            DateComponent::Year,
            DateComponent::Month,
            DateComponent::Day,
        ] => Some(DateOrder::YearMonthDay),

        _ => None,
    }
}

